const Q_COMMERCE_2000=[{"id": "objective>Commerce>2000>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Government policies relating to the establishment and operations of businesses are targeted at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">even spread of facilities and employment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the general improvement of the economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing the profits of business owners</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diversification and expansion of businesses</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The government lays down certain rules and regulations that will help to control and regulate business activities in a country and also to encourage smooth operations because of th inherent intricacies and complexities in the commercial world.</div>", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITY : MEANING AND TYPES"}, {"id": "objective>Commerce>2000>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The share capital value that forms part of the balance sheet total is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">issued share capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">called-up share capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">authorised share capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">paid-up share capital</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is the amount of a company's capital that has been funded by shareholders. Paid-up capital can be less than a company's total capital because a company may not issue all of the shares that it has been authorized to sell.</div>", "topic": "FINANCING BUSINESS : TYPES OF CAPITAL"}, {"id": "objective>Commerce>2000>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Bank overdraft as a short term source of fund is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a current liability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">granted to a newly opened account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">repayable after more than a year</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an overdrawn account</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Overdraft is granted to an individual who operate a current account. It occurs when an individual withdraw more than what he has in his account.Bank overdraft is a current liability, that is usually repaid within the business period. </div>", "topic": "FINANCING BUSINESS : SOURCE OF FINANCE"}, {"id": "objective>Commerce>2000>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The measure of independence available to the individual business units that come together is the main difference between</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">vertical and horizontal integration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">merger and acquisitions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trust and cartel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consortium and amalgamation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Consortium is a temporary alliance of two or more businesses that come together for a specific project or venture. Each business in a consortium retains its independence and continues to operate separately. <br/>  <br/> Amalgamation on the other hand refers to the merging of two or more companies into single entity. In an amalgamation, the individual business units lose their independence and operate as one unified company.</div>", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER"}, {"id": "objective>Commerce>2000>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major factors that facilitate merchandising are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Communication, advertising and banking</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Trading, warehousing and production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Banking, insurance and transportation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Management, insurance and advertising</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major factors that facilitate merchandising are banking, insurance, and transportation. Banking provides the necessary financial support for the purchase and sale of goods. Insurance provides protection against risks associated with the transportation and storage of goods. Transportation ensures the movement of goods from the place of production to the place of consumption.</div>", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES"}, {"id": "objective>Commerce>2000>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer this questions. <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Amina Enterprises</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Balance Sheet as at 30/3/99</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Liabilities</td><td style=\"border:1px solid black;text-align:center;\"> ₦ </td><td style=\"border:1px solid black;text-align:center;\">Assets</td><td style=\"border:1px solid black;text-align:center;\"> ₦ <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Share capital</td><td style=\"border:1px solid black;text-align:center;\">400 000</td><td style=\"border:1px solid black;text-align:center;\"> Land </td><td style=\"border:1px solid black;text-align:center;\">200 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Reserve fund </td><td style=\"border:1px solid black;text-align:center;\">200 000</td><td style=\"border:1px solid black;text-align:center;\"> Buildings</td><td style=\"border:1px solid black;text-align:center;\"> 150 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Creditors</td><td style=\"border:1px solid black;text-align:center;\">110 000</td><td style=\"border:1px solid black;text-align:center;\"> Machinery</td><td style=\"border:1px solid black;text-align:center;\"> 200 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Bills payable</td><td style=\"border:1px solid black;text-align:center;\"> 50 000</td><td style=\"border:1px solid black;text-align:center;\"> Implements</td><td style=\"border:1px solid black;text-align:center;\"> 20 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Undistributed Profits</td><td style=\"border:1px solid black;text-align:center;\"> 45 000</td><td style=\"border:1px solid black;text-align:center;\"> Office fittings</td><td style=\"border:1px solid black;text-align:center;\"> 5 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Wages due </td><td style=\"border:1px solid black;text-align:center;\">5 000</td><td style=\"border:1px solid black;text-align:center;\"> Raw materials</td><td style=\"border:1px solid black;text-align:center;\"> 100 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">Finished goods</td><td style=\"border:1px solid black;text-align:center;\"> 50 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">Debtors</td><td style=\"border:1px solid black;text-align:center;\">20 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">Bills receivable</td><td style=\"border:1px solid black;text-align:center;\"> 15 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">Cash at bank</td><td style=\"border:1px solid black;text-align:center;\"> 45 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">Cash at hand</td><td style=\"border:1px solid black;text-align:center;\"> 5 000</td></tr></table></div> <br/>  <br/> What is the total fixed capital?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦675,000 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦575,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦570,000 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦550,000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The total fixed capital is calculated by adding the share capital and the reserve fund. From the balance sheet, the share capital is ₦400,000 and the reserve fund is ₦200,000. Therefore, the total fixed capital is ₦400,000 + ₦200,000 = ₦600,000. The closest option to this is ₦575,000.</div>", "topic": "FINANCING BUSINESS : TYPES OF CAPITAL"}, {"id": "objective>Commerce>2000>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer this questions. <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Amina Enterprises</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Balance Sheet as at 30/3/99</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Liabilities</td><td style=\"border:1px solid black;text-align:center;\"> ₦ </td><td style=\"border:1px solid black;text-align:center;\">Assets</td><td style=\"border:1px solid black;text-align:center;\"> ₦ <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Share capital</td><td style=\"border:1px solid black;text-align:center;\">400 000</td><td style=\"border:1px solid black;text-align:center;\"> Land </td><td style=\"border:1px solid black;text-align:center;\">200 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Reserve fund </td><td style=\"border:1px solid black;text-align:center;\">200 000</td><td style=\"border:1px solid black;text-align:center;\"> Buildings</td><td style=\"border:1px solid black;text-align:center;\"> 150 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Creditors</td><td style=\"border:1px solid black;text-align:center;\">110 000</td><td style=\"border:1px solid black;text-align:center;\"> Machinery</td><td style=\"border:1px solid black;text-align:center;\"> 200 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Bills payable</td><td style=\"border:1px solid black;text-align:center;\"> 50 000</td><td style=\"border:1px solid black;text-align:center;\"> Implements</td><td style=\"border:1px solid black;text-align:center;\"> 20 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Undistributed Profits</td><td style=\"border:1px solid black;text-align:center;\"> 45 000</td><td style=\"border:1px solid black;text-align:center;\"> Office fittings</td><td style=\"border:1px solid black;text-align:center;\"> 5 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Wages due </td><td style=\"border:1px solid black;text-align:center;\">5 000</td><td style=\"border:1px solid black;text-align:center;\"> Raw materials</td><td style=\"border:1px solid black;text-align:center;\"> 100 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">Finished goods</td><td style=\"border:1px solid black;text-align:center;\"> 50 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">Debtors</td><td style=\"border:1px solid black;text-align:center;\">20 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">Bills receivable</td><td style=\"border:1px solid black;text-align:center;\"> 15 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">Cash at bank</td><td style=\"border:1px solid black;text-align:center;\"> 45 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">Cash at hand</td><td style=\"border:1px solid black;text-align:center;\"> 5 000</td></tr></table></div> <br/> Determine the circulating capital</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">N250,000 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">N245,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N235,000 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">N225,000</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Circulating capital = total current assets = ₦(100,000 + 50,000 + 20,000 + 15,000 + 45,000 + 5,000) = ₦235,000</div>", "topic": "FINANCING BUSINESS : TYPES OF CAPITAL"}, {"id": "objective>Commerce>2000>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The term PLC implies that the shares are available</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">publicly on the stock exchange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">privately on the stock exchange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">to the public at the company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">publicly in commercial banks</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">PLC stands for Public Limited Company. This implies that the shares of the company are available for purchase by the public on the stock exchange. This is different from a private limited company, where shares are only available to a select group of people, usually family and friends.</div>", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES"}, {"id": "objective>Commerce>2000>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The application of division of labour should generally bring about</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase in the variety of goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in the quantity of goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cheapness of goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost efficiency in the production of goods and services</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The advantages of division of labour are: increase in production, time saving, development of greater skill, large scale of production,, creation of employment opportunities  etc.</div>", "topic": "PRODUCTION : DIVISION OF LABOUR & SPECIALISATION"}, {"id": "objective>Commerce>2000>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">On liquidation of a public limited liability company, the residual owners are the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">creditors </div>", "<div style=\"font-family:Cambria;font-size:17px;\">debenture holders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">preference shareholders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ordinary shareholders</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ordinary share comes with limited liability component i.e. at the time of the liquidation each shareholder will be liable to the company up to the extent of the unpaid share capital held by them. Ordinary shares have no specific maturity date unless the company buys it back or delist it. Example of Ordinary Shares.</div>", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : DISSOLUTION AND LIQUIDATION"}, {"id": "objective>Commerce>2000>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Production involves</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">changing the form of goods, moving and making them available as needed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">making goods available where and when needed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the manufacturing of goods and provisions of services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the assembling of all necessary parts to produce a finished product</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Manufacturing of goods is the process of converting raw materials into finished products through various methods such as machining, assembling, and packaging. <br/>  <br/> Also the provision of services activities provide tangible products, such as healthcare, education, and entertainment, which do result in physical product but fulfill a need or demand.</div>", "topic": "PRODUCTION : FACTORS OF PRODUCTION"}, {"id": "objective>Commerce>2000>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these is both merit and demerit in partnership?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The bearing of risk</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Its unlimited nature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The number of partners</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The withdrawal of a major partner</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Having multiple partners can bring in a variety of skills, expertise, and capital, which can benefit the business by enhancing decision-making, expanding resources, and sharing responsibilities. <br/>  <br/> On the other hand, having many partners can also lead to conflicts, slower decision -making processes, and potential disagreements. Managing the interests and contributions of multiple partners can be challenging and may complicate the administration of the partnership.</div>", "topic": "BUSINESS UNIT: PARTNERSHIP : ADVANTAGES AND DISADVANTAGES"}, {"id": "objective>Commerce>2000>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A printer that burns the print images onto the photosensitive drum is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dot matrix printer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">laser printer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">daisywheel printer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">thermal printer</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It's cylindrical drum assembly that is built out of extremely photoconductive substance that is discharged by light photons. This is the core component of a laser printer.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : TYPES OF COMPUTER AND FUNCTIONS"}, {"id": "objective>Commerce>2000>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The insurance principle that requires full disclosure of information on the insured is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">indemnity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">caveat emptor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">subrogation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">uberimae fidei</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Uberrima fides is a Latin phrase meaning \"utmost good faith\" (literally, \"most abundant faith\"). It is the name of a legal doctrine which governs insurance contracts.</div>", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES"}, {"id": "objective>Commerce>2000>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A bank form used to transfer money from personal to creditor's account is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">credit transfer form </div>", "<div style=\"font-family:Cambria;font-size:17px;\">debit transfer form</div>", "<div style=\"font-family:Cambria;font-size:17px;\">customer transfer form</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bank transfer form</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A credit transfer form is a bank form used to transfer money from one's personal account to a creditor's account. It is a method of making a payment from one bank account to another without using physical money.</div>", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLEGES"}, {"id": "objective>Commerce>2000>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A console is a device used in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">moving an indicator on the screen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">forming characters by hearing sensitive ribbon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">holding magnetic tape reel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">communicating between operator and program</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A console is a device that is used to interact with a computer or other electronic system. It typically consists of a keyboard, a mouse, and a display screen. The console can be used to enter commands, to view output, and to control the operation of the system. <br/>  <br/> In the context of a computer, the console is often used to move an indicator on the screen. This indicator is typically a cursor, which is a blinking line or block that shows the user where they are typing. The user can move the cursor around the screen using the keyboard or the mouse.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : ACTIVITIES IN COMPUTER"}, {"id": "objective>Commerce>2000>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The function of a merchant wholesaler is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">buy in bulk, store and sell to retailers as desired</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bring buyers and sellers together</div>", "<div style=\"font-family:Cambria;font-size:17px;\">possess title to the good store and sell to retailers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">find markets for producers</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The merchant wholesaler buys and re-sells goods on their own account taking title to the products they handle and convey the title directly to those they deal with.</div>", "topic": "TRADE (1) : HOME TRADE: WHOLESALE TRADE"}, {"id": "objective>Commerce>2000>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The computer using linear integrated circuit technology coupled with quantification of data in terms of length and distance is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">digital computer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hybrid computer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mainframe computer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">analogue computer</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Analogue computers use continuous data rather than discrete data. They are designed to process data that can vary continuously and are often used for tasks that involve measurement of physical quantities such as length and distance. These computers use linear integrated circuit technology to handle such data, representing it in form that is proportional to the actual physical quantities being measured</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : TYPES OF COMPUTER AND FUNCTIONS"}, {"id": "objective>Commerce>2000>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ocean liners are subdivided into</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cargo liners and tramp liners</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coastal liners and cargo liners</div>", "<div style=\"font-family:Cambria;font-size:17px;\">passenger liners and cargo liners</div>", "<div style=\"font-family:Cambria;font-size:17px;\">passenger liners and tramp liners</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An ocean liner is a ship designed to transport people or cargo from one seaport to another along regular long-distance maritime routes according to a schedule. Liners may also carry mail or may sometimes be used for other purposes (e.g., for pleasure cruises or as hospital ships).</div>", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION"}, {"id": "objective>Commerce>2000>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The current trends in retailing competition in Nigeria are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">self service, after sales service and branding strategies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">branding, enterprising and differentiation of goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">advertising and sales promotion strategies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">after sales services and sales promotion strategies</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">MODERN TRENDS IN RETAILING are Branding,  Self-services, After sales services, Pre-packaging, Vending machine.</div>", "topic": "ELEMENT OF MARKETING : MARKETING MIX"}, {"id": "objective>Commerce>2000>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main factors militating against the rapid growth of trade in Nigeria are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">inadequate transportation network and huge capital outlay</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lack of good transportation network and insecurity of investments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lack of motivation and government attitude towards trade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">huge capital outlay and government attitude to trade</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lack of good transportation network is a fundamental issue because efficient trade relies heavily on robust infrastructure to transport goods and services. Poor transportation infrastructure can lead to higher costs, delays, and inefficiencies which directly hinder trade. <br/>  <br/> Insecurity of investment is another critical factor. Political instability, corruption and lack of legal protections can deter both domestic and foreign investors, reducing the capital available for trade and development.</div>", "topic": "TRADE ( 2) : CUSTOMS, EXCISE, PORTS AUTHORITY ETC."}, {"id": "objective>Commerce>2000>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Mr. Olatunde took up a fire insurance on a property valued at ₦1,000 and the amount insured is ₦800. The property caught fire causing a loss of ₦400. If the insurance was taken with the clause \"with average\", what is the amount to be paid by the insurance company</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦560 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦460</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦420 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦320</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The \"with average\" clause is a clause in an insurance policy that restricts the amount payable to a sum not to exceed the value of the property destroyed and that bears the same proportion to the loss as the face of the policy does to the value of the property insured <br/>        .FORMULA         =              amount insured x loss suffered <br/>                                              ------------------------------------------------ <br/>                                                              value of property <br/>                                                      <br/>                           =                              800 x 400 <br/>                                                             ------------- <br/>                                                                 1000 <br/>                                               =320</div>", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES"}, {"id": "objective>Commerce>2000>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Central Bank differs from commercial banks because it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">renders services to customers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carries out foreign exchange transactions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">issues currencies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">discounts bills</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The objects of the Central Bank are as follows;  <br/> ensure monetary and price stability;  <br/>  issue legal tender currency in Nigeria;  <br/>  maintain external reserves to safeguard the international value of the legal tender currency;  <br/>  promote a sound financial system in Nigeria; and act as Banker and provide economic and financial advice to the Federal Government.</div>", "topic": "AIDS TO TRADE: BANKING : TYPES OF BANK"}, {"id": "objective>Commerce>2000>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Tourists with no fixed address in a town may receive their letters from the post office through a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">poste restante </div>", "<div style=\"font-family:Cambria;font-size:17px;\">recorded delivery</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parcel post </div>", "<div style=\"font-family:Cambria;font-size:17px;\">postmaster</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Poste restante or general delivery is a service where the post office holds mail until the recipient calls for it. It is a common destination for mail for people who are visiting a particular location and have no need, or no way, of having mail delivered directly to their place of residence at that time.</div>", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES"}, {"id": "objective>Commerce>2000>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An invoice can be described as a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">contractual agreement for the sale of goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">receipts containing necessary information about the goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">document specifying quantity, description, prices and total value of purchases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">letter specifying the contractual sales of goods between two parties</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An invoice, bill or tab is a commercial document issued by a seller to a buyer, relating to a sale transaction and indicating the products, quantities, and agreed prices for products or services the seller had provided the buyer.</div>", "topic": "PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING"}, {"id": "objective>Commerce>2000>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The chart above represents the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">marketing mix relationship</div>", "<div style=\"font-family:Cambria;font-size:17px;\">product mix </div>", "<div style=\"font-family:Cambria;font-size:17px;\">promotion mix relationship</div>", "<div style=\"font-family:Cambria;font-size:17px;\">advertising mix relationship</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It gives the marketing mix relationship. The marketing mix is a business tool used in marketing and by marketers. The marketing mix is often crucial when determining a product or brand's offer, and is often associated with the four P's: price, product, promotion, and place.</div>", "topic": "ELEMENT OF MARKETING : MARKETING MIX"}, {"id": "objective>Commerce>2000>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The role of public relations is principally to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sustain good relationship</div>", "<div style=\"font-family:Cambria;font-size:17px;\">advertise a firm's product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carry out publicity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">create good image</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It seeks to create good image for the company and its product in the mind of the customers and other stake holders. Public relation is a device and strategy which the sellers adopt in order to endear himself to the customer in order to win public acceptance.</div>", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE"}, {"id": "objective>Commerce>2000>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The practice whereby soft drink manufacturers give away caps, bags and other items when consumers buy their product is a form of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">marketing strategy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">publicity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sales promotion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">advertising</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sales promotion: A link between personal selling and advertising that stimulate consumer purchase. It includes trade fair, competition, free sample (bearing the firm's logo), premium offer (offer a low value item as a bonus e.g. tooth brush, biro in tooth paste).</div>", "topic": "ELEMENT OF MARKETING : MARKETING MIX"}, {"id": "objective>Commerce>2000>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A group of specialized functions of marketing is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">buying, selling, advertising and packaging</div>", "<div style=\"font-family:Cambria;font-size:17px;\">buying, selling, storing and information</div>", "<div style=\"font-family:Cambria;font-size:17px;\">buying, selling labelling and promotion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">buying, selling, skimming and pricing</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Marketing encompasses a wide range of specialized functions that aim to promote and sell products or services. Among these functions, buying and selling are fundamental activities, while advertising and packaging are critical for creating awareness and attracting customers.</div>", "topic": "ELEMENT OF MARKETING : MEANING AND IMPORTANCE ANF FUNCTIONS"}, {"id": "objective>Commerce>2000>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major condition for obtaining loan in thrift credit and loans cooperative societies is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">provision of collateral security</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a high level of education</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an approved project plan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">possession of a large business</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major condition for obtaining a loan in thrift credit and loans cooperative societies is the provision of collateral security. Collateral security is an asset that a borrower offers to a lender to secure a loan. If the borrower stops making the promised loan payments, the lender can seize the collateral to recoup its losses.</div>", "topic": "FINANCING BUSINESS : SOURCE OF FINANCE"}, {"id": "objective>Commerce>2000>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The type of advertising that seeks to persuade consumers to buy a particular product is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">informative advertising</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mass and specific advertising</div>", "<div style=\"font-family:Cambria;font-size:17px;\">persuasive advertising</div>", "<div style=\"font-family:Cambria;font-size:17px;\">competitive advertising</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is called persuasive advertising. It is a type of product promotion that attempts to influence a consumer in favour of a purchasing particular good or service. A business might engage in informative or persuasive advertising to encourage first time customers to try its product, in addition to reminding customers to purchase a product they have previously bought.</div>", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA"}, {"id": "objective>Commerce>2000>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important advantage of personal selling is that it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">allows sellers to perceive buyer's needs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">takes place easily on the highways</div>", "<div style=\"font-family:Cambria;font-size:17px;\">allows sellers to sell their goods quickly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">takes place without the permission of government</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Personal selling is where businesses use people (the \"sales force\") to sell the product after meeting face-to-face with the customer. The sellers promote the product through their attitude, appearance and specialist product knowledge. Personal selling creates a buyer-seller one-on-one relationship which allows sellers to perceive buyer's needs.</div>", "topic": "AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES"}, {"id": "objective>Commerce>2000>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The stock exchange helps to provide capital for industrial projects because it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">determines value of shares, stocks and other securities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">assists companies to change their securities into cash</div>", "<div style=\"font-family:Cambria;font-size:17px;\">assists government in implementing its monetary policies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">renders agency services to organizations and governments</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A stock exchange is an exchange or stock market where stock brokers and traders can buy and/or sell stocks (also called shares), bonds, and other securities.</div>", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS"}, {"id": "objective>Commerce>2000>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A form of money that has gone out of use is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">commodity money </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bank money</div>", "<div style=\"font-family:Cambria;font-size:17px;\">paper money </div>", "<div style=\"font-family:Cambria;font-size:17px;\">foreign money</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Commodity money is money whose value comes from a commodity of which it is made. Commodity money consists of objects that have value in themselves as well as value in their use as money.</div>", "topic": "MONEY : MEANING AND TYPES OF MONEY"}, {"id": "objective>Commerce>2000>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A shortcoming of the second-tier foreign exchange market in Nigeria is that it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">serves as a mechanism for evaluation an unrealistic exchange rate of the naira</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contribute to flooding the market with foreign essential commodities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contributes to destabilizing national resource</div>", "<div style=\"font-family:Cambria;font-size:17px;\">creates unhealthy competition amongst users of foreign exchange</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The second-tier foreign exchange market in Nigeria was characterized by an unrealistic exchange rate of the naira. This is because the market was not fully liberalized, and the exchange rate was often determined by the government rather than by market forces.</div>", "topic": "TRADE ( 2) : FOREIGN TRADE"}, {"id": "objective>Commerce>2000>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The instrument establishing the Economic Community of West African state in 1975 is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a decree </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a treaty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an act </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a constitution</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It was a treaty. The Economic Community of West African States (ECOWAS) was created by the Treaty of Lagos on May 28, 1975, in Lagos, Lagos State, Nigeria.</div>", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC."}, {"id": "objective>Commerce>2000>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The composite functions of management are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">planning, supervising, communication and directing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coordinating, supervising, staffing and communicating</div>", "<div style=\"font-family:Cambria;font-size:17px;\">planning, controlling, organising and directing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">directing, supervising, motivating and controlling.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Management in businesses and organizations is the function that coordinates the efforts of people to accomplish goals and objectives by using available resources efficiently and effectively. Management includes planning, organizing, staffing, leading or directing, and controlling an organization to accomplish the goal.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : PRINCIPLE"}, {"id": "objective>Commerce>2000>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The three components of staffing are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">recruitment, interview and appointment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">recruitment, selection and placement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">recruitment, test and placement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">recruitment, procurement and appointment</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Staffing is the selection and training of individuals for specific job functions, and charging them with the associated responsibilities. It involves recruitment, selection and placement.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : BUSINESS RESOURCES"}, {"id": "objective>Commerce>2000>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The primary objective of a trade association is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">exchange information and negotiate as a pressure group</div>", "<div style=\"font-family:Cambria;font-size:17px;\">establish easy link with government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">undertake research work on behalf of members</div>", "<div style=\"font-family:Cambria;font-size:17px;\">operates as a group against other groups</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The objectives of trade association are: <br/> - to ensure that members provide good quality services <br/> - to ensure that members charge uniform price <br/> - to maintain professional ethics of their line of trade <br/> - to act as pressure groups in order to influence some government policies <br/> - to assist members who are in need <br/> - to promote trade in particular line of business.</div>", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS"}, {"id": "objective>Commerce>2000>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the functions of the Niger-Basin Commission is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ensure equal treatment of African Nations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">map out regulations that will guide all forms of navigation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">foster close co-operation among West African nations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">guaranteed freedom of navigation for all West African nations</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cameroon, Niger, Nigeria and Chad (the four countries directly containing parts of Lake Chad and its wetlands) signed the Fort Lamy (today N'Djamena) Convention on May 22, 1964, which created the Lake Chad Basin Commission. The Central African Republic joined in 1996, and Libya joined in 2008.  <br/>  The aims of the commission are to regulate and control the use of water and other natural resources in the basin and to initiate, promote, and coordinate natural resource development projects and research.</div>", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC."}, {"id": "objective>Commerce>2000>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The legal aspect of business is designed to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">protect infant industries from collapse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">safeguard consumers from undue business practices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect business organisation and consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encourage free exchange among businesses</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Every business is regulated by some kind of rules and ethics that an organization must obey. These rules are not designed by a firm. In fact, these external laws are made by the country's government to control a firm and ensure proper functioning. Also, it becomes the responsibility of the company to follow the rules.</div>", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION"}, {"id": "objective>Commerce>2000>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">42. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>   The organisational structure above represents</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">line and functional structure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">functional structure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">line and staff structured</div>", "<div style=\"font-family:Cambria;font-size:17px;\">line structure</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The diagram above represents line and staff structure. Line and staff organization is the combination of line or functional whereby a line organization engages experts who are to advice the line managers in the performance of their duties.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE"}, {"id": "objective>Commerce>2000>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An aspect of the law which allows an exclusive right for a limited number of years is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">patent </div>", "<div style=\"font-family:Cambria;font-size:17px;\">trademark</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ratification </div>", "<div style=\"font-family:Cambria;font-size:17px;\">copyright</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A patent is a set of exclusive rights granted by a sovereign state to an inventor or assignee for a limited period of time in exchange for detailed public disclosure of an invention. An invention is a solution to a specific technological problem and is a product or a process.</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT"}, {"id": "objective>Commerce>2000>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The basic elements of a valid contract are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">offer, acceptance, consideration and witness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">offer, acceptance, capacity, legality and consideration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">offer, acceptance, intention, capacity and legality</div>", "<div style=\"font-family:Cambria;font-size:17px;\">offer, intention, acceptance and legality</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The elements of a valid contract are: offer,consideration, acceptance, capacity, legality and consent.</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT"}, {"id": "objective>Commerce>2000>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In an organisation, civic consideration arises from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">its social negative impacts on the community</div>", "<div style=\"font-family:Cambria;font-size:17px;\">its operations within the environment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the profit derived from the environment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the fact that it is registered in that locality</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It arises from the company's operations within the environment and its sense of duty and obligation to it.</div>", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITY : FACTORS"}, {"id": "objective>Commerce>2000>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main difference between nationalization and indigenization in terms of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">efficiency </div>", "<div style=\"font-family:Cambria;font-size:17px;\">profit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">technology </div>", "<div style=\"font-family:Cambria;font-size:17px;\">shareholding</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main difference between nationalization and indigenization lies in the shareholding. Nationalization refers to the process where the government takes control of private industries, while indigenization is a policy enforced by the government to enable native citizens to take control over foreign businesses or assets. Therefore, the difference lies in who holds the shares of the company - the government or the native citizens.</div>", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES"}, {"id": "objective>Commerce>2000>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">After registration, a certificate of trading is usually issued to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Partnership </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Private</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Public company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sole proprietorship</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Public company. It is the certificate issued by the registrar of companies to the public limited company to grant permission to commence it's business.</div>", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES"}, {"id": "objective>Commerce>2000>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A bus driver operating between Lagos and Jos pledged the owner's credit in Benin in order to have the engine repaired and the bill sent to the owner. This is a case of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">agency by necessity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">del credere agency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">agency by ratification </div>", "<div style=\"font-family:Cambria;font-size:17px;\">agency by estsoppel</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is a type of relationship whereby one party can make essential decisions for another party. Agency by necessity is recognized in the courts and typically applies when one party is unable to make. </div>", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : AGENCY IN SALES OF GOODS ACT"}, {"id": "objective>Commerce>2000>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A chamber of commerce is any association made up of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">merchants </div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufacturers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">entrepreneurs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">importers</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A chamber of commerce is a non-profit organization that promotes the interests of businesses and professionals in a particular area. It is typically made up of businesses of all sizes, from small shops to large corporations. The goal of a chamber of commerce is to help businesses succeed by providing them with resources, networking opportunities, and advocacy</div>", "topic": "TRADE ASSOCIATION : CHAMBER OF COMMERCE"}, {"id": "objective>Commerce>2000>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The first known legislation to protect consumer right in Nigeria is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Usury laws </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sale of goods act</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hire purchase act </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Food and drugs act</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The first known legislation to protect consumer rights in Nigeria is the 'Food and Drugs Act'. This act was designed to protect consumers from harmful, misbranded, adulterated, or falsely advertised food and drugs.</div>", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION"}];
